/* watchdog.h - Watchdog Timer Driver */
#ifndef WATCHDOG_H
#define WATCHDOG_H

#include <stdint.h>
#include <stdbool.h>

#define WDT_MIN_TIMEOUT_MS   1U
#define WDT_MAX_TIMEOUT_MS   32000U
#define WDT_DEFAULT_TIMEOUT  5000U
#define WDT_FEED_MAGIC       0xAAAA5555U

typedef void (*wdt_warning_cb_t)(uint32_t remaining_ms);

/* BREAKING: wdt_feed now requires magic token to prevent accidental feeds */
void     wdt_init(uint32_t timeout_ms);
void     wdt_feed(uint32_t magic_token);
void     wdt_set_warning_callback(wdt_warning_cb_t cb, uint32_t warn_ms);
bool     wdt_is_enabled(void);
uint32_t wdt_get_remaining_ms(void);
void     wdt_disable(void);

#endif /* WATCHDOG_H */

